example.code:
class UserService:
    def get_user(self, user_id: str) -> User: ...

@v1.get("/users/{user_id}")
async def get_user_v1(user_id: str, svc: UserService = Depends()):
    user = svc.get_user(user_id)
    return {"id": user.id, "name": user.name}

@v2.get("/users/{user_id}")
async def get_user_v2(user_id: str, svc: UserService = Depends()):
    user = svc.get_user(user_id)
    return {"data": {"id": user.id, "name": user.name}, "meta": {"v": 2}}
